export type Couple = {
  bride: string;
  groom: string;
  place: string;
  img: MatImageRecord;
  slug?: string;
  story?: FeaturedStory;
  /** When set, the slug page hero shows a playable feature reel (poster +
   *  centred play affordance → native controls on click) instead of the
   *  static cover image. Audio plays when the visitor presses play. */
  heroVideo?: {
    /** Path under /public — e.g. /video/featured/<slug>/highlight.mp4 */
    src: string;
    /** Path under /public — used as <video poster> and as a fallback. */
    poster: string;
    /** Display duration, e.g. "3:00" — shown beside the play affordance. */
    duration: string;
  };
};

